from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.backends import default_backend
from cryptography.hazmat.primitives import padding
import os
from base64 import b64encode, b64decode

# Configuration for encryption
CONFIG = {
    'encryption_key': b'secure_application_key',  # This should be securely stored and accessed
    'salt': os.urandom(16),
    'iterations': 100000
}

def derive_key(password, salt, iterations):
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=salt,
        iterations=iterations,
        backend=default_backend()
    )
    return kdf.derive(password)

def encrypt_credit_card(credit_card_number):
    key = derive_key(CONFIG['encryption_key'], CONFIG['salt'], CONFIG['iterations'])
    iv = os.urandom(16)
    cipher = Cipher(algorithms.AES(key), modes.CBC(iv), backend=default_backend())
    encryptor = cipher.encryptor()
    padder = padding.PKCS7(algorithms.AES.block_size).padder()
    padded_data = padder.update(credit_card_number.encode()) + padder.finalize()
    encrypted = encryptor.update(padded_data) + encryptor.finalize()
    return b64encode(iv + encrypted).decode('utf-8')

def decrypt_credit_card(encrypted_data):
    key = derive_key(CONFIG['encryption_key'], CONFIG['salt'], CONFIG['iterations'])
    encrypted_data = b64decode(encrypted_data)
    iv = encrypted_data[:16]
    encrypted = encrypted_data[16:]
    cipher = Cipher(algorithms.AES(key), modes.CBC(iv), backend=default_backend())
    decryptor = cipher.decryptor()
    padded_data = decryptor.update(encrypted) + decryptor.finalize()
    unpadder = padding.PKCS7(algorithms.AES.block_size).unpadder()
    data = unpadder.update(padded_data) + unpadder.finalize()
    return data.decode('utf-8')